sys_script_include.script:
var AN_ReportGenerator = Class.create();

AN_ReportGenerator.prototype = {

    buildReport: function(scanId) {

        var scan = new GlideRecord("x_1920012_apprai_0_an_scan");

        if (!scan.get(scanId))
            return "<h1>Scan not found</h1>";

        var score = new GlideRecord("x_1920012_apprai_0_an_scorecard");

        score.addQuery("scan", scanId);
        score.query();

        if (!score.next())
            return "<h1>Scorecard not found</h1>";

        var html = "";

        html += "<html>";
        html += "<head>";

        html += "<style>";

        html += "body{font-family:Arial;padding:40px;background:#f7f7f7;}";

        html += ".container{background:white;padding:30px;border-radius:8px;}";

        html += "h1{color:#0b5cad;}";

        html += "table{width:100%;border-collapse:collapse;margin-top:15px;}";

        html += "th,td{border:1px solid #ccc;padding:8px;text-align:left;}";

        html += "th{background:#0b5cad;color:white;}";

        html += ".section{margin-top:30px;}";

        html += ".score{font-size:26px;font-weight:bold;color:#2e7d32;}";

        html += ".footer{margin-top:40px;color:gray;font-size:12px;}";

        html += "</style>";

        html += "</head>";

        html += "<body>";

        html += "<div class='container'>";

        html += "<h1>AppraiseNow Audit Report</h1>";

        html += "<hr>";

        html += "<h2>Application</h2>";

        html += "<table>";

        html += "<tr><th>Application</th><td>" + scan.app_name + "</td></tr>";
        html += "<tr><th>Scan Number</th><td>" + scan.number + "</td></tr>";
        html += "<tr><th>Status</th><td>" + scan.status + "</td></tr>";
        html += "<tr><th>Overall Score</th><td class='score'>" + score.overall_score + "</td></tr>";
        html += "<tr><th>Grade</th><td>" + score.grade + "</td></tr>";

        html += "</table>";

        html += "<div class='section'>";

        html += "<h2>Score Breakdown</h2>";

        html += "<table>";

        html += "<tr><th>Dimension</th><th>Score</th></tr>";

        html += "<tr><td>Security</td><td>" + score.security_score + "</td></tr>";

        html += "<tr><td>Performance</td><td>" + score.performance_score + "</td></tr>";

        html += "<tr><td>Quality</td><td>" + score.quality_score + "</td></tr>";

        html += "<tr><td>Maintainability</td><td>" + score.maintainability_score + "</td></tr>";

        html += "<tr><td>Update Set</td><td>" + score.update_set_score + "</td></tr>";

        html += "</table>";

        html += "</div>";

        html += "<div class='section'>";

        html += "<h2>AI Summary</h2>";

        html += "<p>" + score.ai_summary + "</p>";

        html += "<h3>Strengths</h3>";

        html += "<pre>" + score.ai_strengths + "</pre>";

        html += "<h3>Risks</h3>";

        html += "<pre>" + score.ai_risks + "</pre>";

        html += "<h3>Recommendations</h3>";

        html += "<pre>" + score.ai_reccomendations + "</pre>";

        html += "<h3>Grade Reason</h3>";

        html += "<p>" + score.ai_grade_reason + "</p>";

        html += "</div>";

        html += "<div class='section'>";

        html += "<h2>Findings</h2>";

        html += "<table>";

        html += "<tr>";
        html += "<th>Severity</th>";
        html += "<th>Dimension</th>";
        html += "<th>Title</th>";
        html += "<th>Description</th>";
        html += "</tr>";

        var finding = new GlideRecord("x_1920012_apprai_0_an_finding");

        finding.addQuery("scan", scanId);

        finding.query();

        while (finding.next()) {

            html += "<tr>";

            html += "<td>" + finding.severity + "</td>";

            html += "<td>" + finding.dimension + "</td>";

            html += "<td>" + finding.title + "</td>";

            html += "<td>" + finding.description + "</td>";

            html += "</tr>";

        }

        html += "</table>";

        html += "</div>";

        html += "<div class='footer'>";

        html += "Generated by AppraiseNow • " + new GlideDateTime().getDisplayValue();

        html += "</div>";

        html += "</div>";

        html += "</body>";

        html += "</html>";

        return html;

    },

    type: "AN_ReportGenerator"

};
